/**
 * Base64-embedded JPEG — a square crop of the exact globe image the home
 * page hero section uses (public/hero/hero-bg.png), pre-cropped and resized
 * to what the Professional Affiliation Card actually needs. Inlined as a
 * source constant rather than read from the filesystem at render time:
 * Next.js only bundles public/ assets that its build-time file tracing can
 * statically discover, and a dynamic fs.readFileSync(path.join(...)) call
 * inside a serverless function is not guaranteed to be traced — inlining
 * removes that failure mode entirely, at the cost of a larger source file.
 */
export const CARD_GLOBE_JPEG_BASE64 =
  "";
